								//	맵 Clear하지 말고 업무종료
								//------------------------------------------------------------------------------------------------------------
								
								szMsg = "[" + szOperationName + "] 차량스케줄["+szYD_CAR_SCH_ID+"]이 존재하고 전문의 착지개소코드["+szARR_WLOC_CD+"]와 차량스케줄의 발지개소코드["+szCURR_SPOS_WLOC_CD+"]가 같고 ";
