	    boolean blnRtnVal               = true;
	    
	    String szMsg           = "";
	    String szMethodName    		= "makeCarUdWrkBookAB";
	    String szOperationName    = "차량하차작업예약생성";
	    
	    String szQuery         = "";
	    
	    String szYD_CAR_SCH_ID = "";
	    String szYD_WBOOK_ID   = "";
