	    	//야드구분 = 목표야드구분
	    	szYD_GP         = ydDaoUtils.paraRecChkNull(recOutTemp, "YD_AIM_YD_GP");
	    	//야드동구분 = 목표동구분
	    	szYD_BAY_GP     = ydDaoUtils.paraRecChkNull(recOutTemp, "YD_AIM_BAY_GP");
	    	
