	/**
	 *      [A] 오퍼레이션명 : 후판/코일 제품사외창고도착실적 (DMYDR043)
	 *  
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param msgRecord
	 * @return
	 * @throws JDTOException
	 */
	public void procPlGdsDistShipArrWr(JDTORecord msgRecord)throws JDTOException  {
		
		// DAO 및 UTIL 객체 생성
		YmEtcDao YmEtcDao     	  = new YmEtcDao();
		// 레코드 선언
		JDTORecord recIn          = null;
		
	    String szMsg              = "";
	    String szMethodName       = "procPlGdsDistShipArrWr";	    	        	
	    String szRcvTcCode        = null;

	    int intRtnVal 			  = 0;

	    szRcvTcCode = ydUtils.getTcCode(msgRecord);
	    if(szRcvTcCode == null){
			szMsg = szSessionName + "::" + szMethodName + "() TC Code Error (" + szRcvTcCode + ")";
			ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
			return ;
		}
		
		if(bDebugFlag){
			szMsg="전문수신 : TCCODE=" +szRcvTcCode ;
			ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
		}
		
	    try{
	    	//=============================================================
	    	// 권오창
	    	// 2009.11.05
	    	//
	    	// Log 테이블 등록 
	    	// 야드는 X로 일단 두었음 수정해야됨
	    	//=============================================================
	    	szMsg = "[출하] 후판/코일 제품사외창고도착실적 수신";
	    	ydUtils.putLogMsg("X", YdConstant.YD_MONITORING_CHANNEL_K, szMsg, "", "", "", "I", "A", "I", szRcvTcCode, szSessionName, szMethodName);
	    	
	    	/*
	    	YD_GP			야드구분	CHAR	1	Y		
	    	TRANSMIT_DATE	전송일자	CHAR	8			
	    	SEND_SEQ		전송순번	NUMBER	5			
	    	CANCEL_YN		취소유무	CHAR	1	Y	Y: 취소 , N: 지시	
	    	FR_GBN			사외창고구분 CHAR  2   4A-삼우, 4B-지전 , VC-(주)삼일 , VD-한원스틸 , VE-(주)중앙운수
	    	TABLE : TB_DM_SETTLEDOWNWRSLTIFTEMP
			*/
	    	
	    	String sYdGp			= ydDaoUtils.paraRecChkNull(msgRecord, "YD_GP");
	    	String sTransmitDate 	= ydDaoUtils.paraRecChkNull(msgRecord, "TRANSMIT_DATE");
	    	String sSendSeq     	= ydDaoUtils.paraRecChkNull(msgRecord, "SEND_SEQ");
	    	String sCancelYn     	= ydDaoUtils.paraRecChkNull(msgRecord, "CANCEL_YN");
	    	String sFrGbn	     	= ydDaoUtils.paraRecChkNull(msgRecord, "FR_GBN");
	    	
	    	if("N".equals(sCancelYn)){
		    	
	    		// 레코드 생성
				recIn = JDTORecordFactory.getInstance().create();
				recIn.setField("TRANSMIT_DATE", sTransmitDate);
				recIn.setField("SEND_SEQ", sSendSeq);
				
				String sFrYdGp	= "";
				String sYdLoc	= "";
				
				if("".equals(sFrGbn)){
					sFrYdGp = sYdGp;
					sYdLoc  = sYdGp+"A11111111";
				}else{
					sFrYdGp = sYdGp;
					sYdLoc  = sFrGbn+"11111111";
				}

				recIn.setField("YD_GP", sFrYdGp);
				recIn.setField("YD_STR_LOC", sYdLoc);

				if(sYdGp.equals("4")){
					intRtnVal = YmEtcDao.uptYmEtcDao(recIn, 4);  //후판 사외창고 인경우
					
					if(intRtnVal < 0){
						szMsg = "PLATECOMM[PLATE작업지시] Error :: TRANSMIT_DATE(" + sTransmitDate + ") SEND_SEQ(" + sSendSeq + ") [" + intRtnVal + "]" + "PARAMETER ERROR";
						ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
						return ;
					} else if(intRtnVal == 0){
						szMsg = "PLATECOMM[PLATE작업지시] Error :: TRANSMIT_DATE(" + sTransmitDate + ") SEND_SEQ(" + sSendSeq + ")[" + intRtnVal + "]" + "DO NOT EXIST";
						ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
						return ;
					}
					
				}else if(sYdGp.equals("V")){
					intRtnVal = YmEtcDao.uptYmEtcDao(recIn, 12); //열연 사외창고 인경우
					
					if(intRtnVal < 0){
						szMsg = "COILCOMM[COIL작업지시] Error :: TRANSMIT_DATE(" + sTransmitDate + ") SEND_SEQ(" + sSendSeq + ") [" + intRtnVal + "]" + "PARAMETER ERROR";
						ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
						return ;
					} else if(intRtnVal == 0){
						szMsg = "COILCOMM[COIL작업지시] Error :: TRANSMIT_DATE(" + sTransmitDate + ") SEND_SEQ(" + sSendSeq + ")[" + intRtnVal + "]" + "DO NOT EXIST";
						ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
						return ;
					}
				}
	    	}
	    	
		}catch(Exception e){
			szMsg="후판/코일 제품사외도착실적 처리 Error:" +e.getMessage();
			ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
			throw new DAOException(e);
		}

		szMsg="후판/코일 제품사외도착실적 처리("+szMethodName+") 완료";
		ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
	}// end of procPlGdsDistShipArrWr()
	
	
	
