	/**
	 *      [A] 오퍼레이션명 : 야드적치열맵활성화 UPDATE
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param  JDTORecord inRec parameter record
	 * @return
	 * @ejb.transaction type="RequiresNew"
	 */		
	public void updYdStkColTX(JDTORecord recInTemp) throws DAOException  {
		

		try {
			int intRtnVal       		= 0;
			YdPlateCommDAO commDao = new YdPlateCommDAO();
			
			String szQueryId = recInTemp.getFieldString("QUERY_ID");
			
			intRtnVal = commDao.update(recInTemp, szQueryId);	    	
	    	
		} catch (Exception e) {
			// Exception발생시 EJBServiceException의 상속클래스로 throw합니다.
			throw new DAOException(e.getMessage(), e);			
		}
		
		return;
	};
		
	

