    	String szMethodName					= "traillerMoveSch";
    	String sYD_SCH_CD					= "";
    	String sSTL_NO						= "";
    	String sTO_YD_SCH_CD				= "";
    	String sYD_USER_ID					= "";
    	String sYD_WBOOK_ID					= "";
    	String sYD_WBOOK_ID2				= "";
