	public String procMatlCarCancel(String szTRN_EQP_CD)throws DAOException  {
 
		YdCarSchDao ydCarSchDao = new YdCarSchDao(); 
		YdStkColDao ydStkColDao = new YdStkColDao();
		JDTORecordSet rsResult   = null;
		JDTORecord    recInTemp  = null;
		JDTORecord    recOutTemp = null; 
		
	    int intRtnVal 			 = 0;
	    String szMsg             = "";
	    String szMethodName      = "procMatlCarCancel";
	    String szYD_CAR_SCH_ID   = "";
	    String szYD_CARLD_WRK_BOOK_ID = "";
	    String szOperationName = "소재차량출발대기장처리";
		String szMSG_ID =""; 
		
	    try{
	    	
	    	//------------------------------------------------------------------------------------------------------------
	    	//	파라미터 확인
	    	//------------------------------------------------------------------------------------------------------------

	    	//수신한 전문내용 출력
	    	szMsg = "[" + szOperationName + "] --------------------------------- 메소드 시작 : 전문내용 확인 시작 ---------------------------------";
			ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
		 
	    	//------------------------------------------------------------------------------------------------------------
	    	//	운송장비코드로 차량스케줄 조회
	    	//------------------------------------------------------------------------------------------------------------
	    	
			rsResult 	= JDTORecordFactory.getInstance().createRecordSet("");
			recInTemp 	= JDTORecordFactory.getInstance().create();
			recInTemp.setField("TRN_EQP_CD", szTRN_EQP_CD);
			/*com.inisteel.cim.yd.dao.ydcarschdao.YdCarschDao.getYdCarschDaoWrkBookTrnEqpCd*/
			intRtnVal = ydCarSchDao.getYdCarsch(recInTemp, rsResult, 415);
			
			if(intRtnVal <= 0) {	 
				szMsg= "[" + szOperationName + "] 차량스케줄 조회 시 오류발생 - 작업예약["+intRtnVal+"]이 존재합니다.";
				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
	 
			}else{
			
				rsResult.absolute(1);
				recOutTemp = JDTORecordFactory.getInstance().create();
				recOutTemp.setRecord(rsResult.getRecord());
				
				//작업예약ID
				szYD_CARLD_WRK_BOOK_ID = ydDaoUtils.paraRecChkNull(recOutTemp, "YD_WBOOK_ID");
				//차량스케줄ID
				szYD_CAR_SCH_ID = ydDaoUtils.paraRecChkNull(recOutTemp, "YD_CAR_SCH_ID");
				
				
				
				
		    	//------------------------------------------------------------------------------------------------------------
				//	예약된 차량정지POINT 삭제처리
				//------------------------------------------------------------------------------------------------------------
				
				szMsg = "[" + szOperationName + "] 운송장비코드로 예약된 차량정비Point 삭제 시작";
				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
				 
				
				JDTORecord recPara = JDTORecordFactory.getInstance().create();
				//운송장비코드
				recPara.setField("TRN_EQP_CD",              szTRN_EQP_CD);
				intRtnVal = ydStkColDao.updYdStkcol1(recPara, 1);
				
				if( intRtnVal <= 0 ) {
					szMsg = "[" + szOperationName + "] 운송장비코드["+szTRN_EQP_CD+"] - 예약된 차량정지point 삭제 시 오류발생 - 반환값 : " + intRtnVal;
					ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
				}else if( intRtnVal == 0 ) {
					szMsg = "[" + szOperationName + "] 운송장비코드["+szTRN_EQP_CD+"] - 예약된 차량정지point 삭제 시 예약된 차량정지point가 존재하지 않습니다.";
					ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
				}
				
				szMsg = "[" + szOperationName + "] 운송장비코드로 예약된 차량정비Point 삭제 완료 - 반환값 : " + intRtnVal;
				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
				
				//------------------------------------------------------------------------------------------------------------
				
				//------------------------------------------------------------------------------------------------------------
				//	차량스케줄 삭제처리
				//------------------------------------------------------------------------------------------------------------
				
				szMsg = "[" + szOperationName + "] 차량스케줄["+szYD_CAR_SCH_ID+"]이 존재하므로 삭제 시작";
				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
				
				recInTemp = JDTORecordFactory.getInstance().create();
				recInTemp.setField("YD_CAR_SCH_ID", 		szYD_CAR_SCH_ID);
				recInTemp.setField("DEL_YN", 				"Y");
				recInTemp.setField("MODIFIER", 				"CarCancel");
				
				String szRtnMsg		= DaoManager.updYdCarsch(recInTemp, 0);
				
				szMsg = "[" + szOperationName + "] 차량스케줄["+szYD_CAR_SCH_ID+"]이 존재하므로 삭제 완료 - 메세지 : " + szRtnMsg;
				ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
				
				//------------------------------------------------------------------------------------------------------------
				
				if( !szYD_CARLD_WRK_BOOK_ID.equals(""))	{
				
					//------------------------------------------------------------------------------------------------------------
					//	작업예약삭제
					//------------------------------------------------------------------------------------------------------------
					
					szMsg = "[" + szOperationName + "] 상차작업예약["+szYD_CARLD_WRK_BOOK_ID+"]이 존재하므로 삭제 시작";
					ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
					
					szRtnMsg	= YdCommonUtils.delYdWrkbookNMtl(szYD_CARLD_WRK_BOOK_ID, "CarCancel");
					
					szMsg = "[" + szOperationName + "] 상차작업예약["+szYD_CARLD_WRK_BOOK_ID+"]이 존재하므로 삭제 완료 - 메세지 : " + szRtnMsg;
					ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
					
					//------------------------------------------------------------------------------------------------------------
					
					
					//------------------------------------------------------------------------------------------------------------
					//	준비스케줄복구
					//------------------------------------------------------------------------------------------------------------
					
					szMsg = "[" + szOperationName + "] 상차작업예약["+szYD_CARLD_WRK_BOOK_ID+"]과 관련된 준비스케줄 복구 시작";
					ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
					
					szRtnMsg	= YdCommonUtils.restorePrepSch(szYD_CARLD_WRK_BOOK_ID, "CarCancel");
					
					szMsg = "[" + szOperationName + "] 상차작업예약["+szYD_CARLD_WRK_BOOK_ID+"]과 관련된 준비스케줄 복구 완료 - 메세지 : " + szRtnMsg;
					ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
					
					//------------------------------------------------------------------------------------------------------------
					
				}
	    	
			}
	    	

		}catch(Exception e){
			szMsg="소재차량출발대기장처리 Error:" +e.getMessage();
			ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.ERROR);
			m_ctx.setRollbackOnly();
			throw new DAOException(szMsg);
		}

		
		szMsg="소재차량출발대기장처리("+szMethodName+") 완료";
		ydUtils.putLog(szSessionName, szMethodName, szMsg, YdConstant.DEBUG);
		return YdConstant.RETN_CD_SUCCESS;
	
	}// end of procMatlCarCancel()
	
 
