    /**
     * JDTORecord 가 가지는 name parameter에 대한 값을 리턴한다.
     * @param data
     * @param name
     * @return
     */
    private String getField(JDTORecord data, String name) {
    	if(data == null){
    		return "";	
    	}else{
       	return StringHelper.evl(data.getFieldString(name), "").trim();
    	}
    }
    
    
