										outRec.setField("MQ_TC_CREATE_DDTT"    , sCurrDate     		); //JMSTC생성일시
										outRec.setField("TRANS_WORD_DATE"		,szTRANS_ORD_DATE);
										outRec.setField("TRANS_WORD_SEQNO" 		,szTRANS_ORD_SEQNO);
										outRec.setField("CAR_NO"				,szCAR_NO);
