	/**
	 *      [A] 오퍼레이션명 : 관리되지않는 개소코드 차량 출발처리 
	 *  	
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param rcvMsg,logId,modifier
	 * @return 
	 * @throws DAOException
	 */
	
	public void procMatlCarLevUnmanageWloc(JDTORecord rcvMsg,String logId,String modifier) throws DAOException {
		String methodNm = "관리되지않는 개소코드 차량 출발처리  [CarMvHdSeEJB.procMatlCarLevUnmanageWloc] < ";

		try{
			slabUtils.printLog(logId, methodNm, "S+");
		
			String trnEqpCd 		 = slabUtils.trim(rcvMsg.getFieldString("TRN_EQP_CD"));			//장비번호
			String arrWlocCd 		 = slabUtils.trim(rcvMsg.getFieldString("ARR_WLOC_CD"));			//착지개소
			String trnWrkFullvoidGp  = slabUtils.trim(rcvMsg.getFieldString("TRN_WRK_FULLVOID_GP"));	//공차영차 구분
	
			if(YdCommonUtils.getABLocationInfo(arrWlocCd) && YdConstant.TRN_WRK_VOID.equals(trnWrkFullvoidGp)){
				slabUtils.printLog(logId,"AB열연으로 공차(상차)출발 시 상차LOT편성을 AB열연 모듈에서 처리하므로 업무처리 종료. ", "SL");
			} else if(YdConstant.TRN_WRK_VOID.equals(trnWrkFullvoidGp)){
				slabUtils.printLog(logId,"착지개소코드 ["+arrWlocCd+"]가 AB열연 or 관리되지 않는 착지개소코드이면 공차출발 시 하위 모듈에서 운송장비코드["+trnEqpCd+"]로 차량스케줄만 생성 후 업무 종료 ", "SL");
				chkWlocCdLotCompReNew(rcvMsg,logId,modifier);			
			} else if(YdConstant.TRN_WRK_FULL.equals(trnWrkFullvoidGp)){
				slabUtils.printLog(logId,"착지개소코드 ["+arrWlocCd+"]가 AB열연 or 관리되지 않는 착지개소코드이면 영차출발 시 차량스케줄의 상태값을 하차출발로 변경 처리["+trnEqpCd+"] ", "SL");
				//차량 하차출발상태 변경
				updYdCarSchToUDLevByTrnEqpCd(trnEqpCd,null,logId,modifier);

				//소재차량 도착포인트 요구 호출
				YdCommonUtils.callMatlCarArrPntReq(trnEqpCd, arrWlocCd, trnWrkFullvoidGp, "N", this);
				
				slabUtils.printLog(logId,"AB열연 or 관리되지 않는 야드이므로 영차출발 시 차량스케줄의 상태값을 하차출발로 변경 처리를 완료성공 - 하차LOT편성은 AB열연 모듈에서 진행됨으로 메소드 리턴처리. ", "SL");
			}
			

			slabUtils.printLog(logId, methodNm, "S-");

		} catch (DAOException e) {
			throw e;
		} catch (Exception e) {
			throw new DAOException(slabUtils.makeErrorLog(logId, methodNm, e));
		}
		
	}
	
	/**
	 *      [A] 오퍼레이션명 : 개소코드구분 및 상차Lot편성 Renewal
	 *  	
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param rcvMsg,logId,modifier
	 * @return 
	 * @throws DAOException
	 */
	public void chkWlocCdLotCompReNew(JDTORecord rcvMsg,String logId,String modifier) throws DAOException {
		String methodNm = "개소코드구분 및 상차Lot편성 Renewal [CarMvHdSeEJB.chkWlocCdLotCompReNew] < ";

		try{
			slabUtils.printLog(logId, methodNm, "S+");
		
			String trnEqpCd 		 = slabUtils.trim(rcvMsg.getFieldString("TRN_EQP_CD"));			//장비번호
			String sposWlocCd 		 = slabUtils.trim(rcvMsg.getFieldString("SPOS_WLOC_CD"));			//발지개소
			String sposYdPntCd 		 = slabUtils.trim(rcvMsg.getFieldString("SPOS_YD_PNT_CD"));		//발지포인트코드
			String arrWlocCd 		 = slabUtils.trim(rcvMsg.getFieldString("ARR_WLOC_CD"));			//착지개소
			String trnWrkFullvoidGp  = slabUtils.trim(rcvMsg.getFieldString("TRN_WRK_FULLVOID_GP"));	//공차영차 구분
			String trnEqpStkCapa	 = slabUtils.trim(rcvMsg.getFieldString("TRN_EQP_STK_CAPA"));		//차량 적재능력
			
			String spTruckLoadingLocTp = "H";
			String pntDmdDt			 = YdUtils.getCurDate("yyyyMMddHHmmss");
			String ydDirectCarldGp = slabUtils.trim(rcvMsg.getFieldString("YD_DIRECT_CARLD_GP"));//
			String ydCarldLevLoc   = "";
			
			boolean isEjbCall 	     = "Y".equals(slabUtils.trim(rcvMsg.getFieldString("IS_EJB_CALL"))) ? true : false;//하위 모듈 EJB Call 여부
			boolean isYdAutoLot      = false;

			//발지개소코드, 발지개소Point를 야드저장위치로 변환(출발지 위치)
			JDTORecord    recPara  = JDTORecordFactory.getInstance().create();
			recPara.setField("WLOC_CD", sposWlocCd);
			recPara.setField("YD_PNT_CD", sposYdPntCd);
			JDTORecordSet recSetRes = commDao.select(recPara, "com.inisteel.cim.yd.dao.ydstkcoldao.YdStkcolDao.getYdStkcolWLocCdandPntCd", logId, methodNm, "적치열 조회"); 
			
			if(recSetRes.size() >0 ) {
				slabUtils.printLog(logId,"발지개소["+sposWlocCd+"] 및 포인트 코드["+sposYdPntCd+"] 적치열로 변환", "SL");
				ydCarldLevLoc = slabUtils.trim(recSetRes.getRecord(0).getFieldString("YD_CARLD_STOP_LOC"));
			} 
			
			//착지가 연주 or C#3스카핑야드 or AB 열연 아닌 관리되지 않는 개소코드 
			//자동 LOT 편성 사용 안하므로 IF문 그냥 제거..
			if(YdConstant.WLOC_CD_C_SLAB_YARD.equals(arrWlocCd)
				|| YdConstant.WLOC_CD_PORT_SLAB_YARD.equals(arrWlocCd) 
				|| YdConstant.WLOC_CD_A_PLATE_PLANT.equals(arrWlocCd) 
				|| YdConstant.WLOC_CD_B_PLATE_PLANT.equals(arrWlocCd)
				|| YdConstant.WLOC_CD_C_HR_PLANT.equals(arrWlocCd)){

	
		    	//차량스케줄 생성
		    	recPara = JDTORecordFactory.getInstance().create();
				recPara.setField("REGISTER",         modifier);
				recPara.setField("YD_EQP_WRK_STAT",  "U");										//야드설비작업상태
				recPara.setField("YD_EQP_ID",        YdConstant.YD_TS_CAR_EQP_ID);				//야드설비ID
				recPara.setField("TRN_EQP_CD",       trnEqpCd);								//운송장비코드
				recPara.setField("YD_CAR_USE_GP",    YdConstant.YD_CAR_USE_GP_TS);				//차량사용구분
				recPara.setField("SPOS_WLOC_CD",     arrWlocCd);								//발지개소코드
				recPara.setField("YD_CARLD_LEV_LOC", ydCarldLevLoc);						//야드상차출발위치
				recPara.setField("YD_CARLD_LEV_DT",  YdUtils.getCurDate("yyyyMMddHHmmss"));		//상차출발일시
				recPara.setField("YD_BAYIN_WO_SEQ",  YdConstant.YD_BAYIN_WO_SEQ_DEFAULT);		//입동지시순번 - 기본값으로 설정(9)
				recPara.setField("YD_CAR_PROG_STAT", YdConstant.YD_CARLD_LEV);					//상차출발상태
				//recPara.setField("YD_CARLD_STOP_LOC", szYD_CARLD_STOP_LOC);						//야드상차정지위치 (직상차 제외)
				
				
				
				String rtnMsg = YdCommonUtils.mkCarSch(recPara);
				
				if( !YdConstant.RETN_CD_SUCCESS.equals(rtnMsg) ) {
					slabUtils.printLog(logId,"C연주슬라브야드 개소코드["+arrWlocCd+"] : 장비코드["+trnEqpCd+"] 차량 스케줄생성 시 오류발생", "SL");
					
					m_ctx.setRollbackOnly();
					throw new DAOException("C연주슬라브야드 개소코드["+arrWlocCd+"] : 장비코드["+trnEqpCd+"] 차량 스케줄생성 시 오류발생");
				}
				
				//소재차량도착Point요구 호출
				YdCommonUtils.callMatlCarArrPntReq(trnEqpCd, arrWlocCd, "Y", this);
				
				return;
			}
			

			slabUtils.printLog(logId, methodNm, "S-");

		} catch (DAOException e) {
			throw e;
		} catch (Exception e) {
			throw new DAOException(slabUtils.makeErrorLog(logId, methodNm, e));
		}
		
	}
	
	/**
	 *      [A] 오퍼레이션명 : 통합야드 모바일 push 알림 procedure 호출 
	 *  	
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param trnEqpCd,trnWrkFullvoidGp,logId
	 * @return 
	 * @throws DAOException
	 */
	public void callPushCalltoTotYd(String trnEqpCd,String trnWrkFullvoidGp, String logId) throws DAOException {
		String methodNm = "통합야드 모바일 push 알림 procedure 호출 [CarMvHdSeEJB.callPushCalltoTotYd] < ";

		try{
			slabUtils.printLog(logId, methodNm, "S+");
		
			
			String message = "";
			String ext = "";
			if(YdConstant.TRN_WRK_VOID.equals(trnWrkFullvoidGp)){
				message = "("+trnEqpCd+")가%20상차를%20위해%20통합야드로%20출발.동지정%20필요";
				ext =  "1|%20|" + trnEqpCd;
			}
			else {
				message = "("+trnEqpCd+")가%20하차를%20위해%20통합야드로%20출발.동지정%20필요";
				ext =  "A|%20|" + trnEqpCd;
			}
			Object[] inParam = {message, ext};
    		int[] inParamIndex = {1,2};
			
    		YdPlateCommDAO commDao = new YdPlateCommDAO();
			commDao.callProcedure(inParam, inParamIndex, "com.inisteel.cim.yd.common.dao.YdCommDao.callMobilePush");
			

			slabUtils.printLog(logId, methodNm, "S-");

		} catch (DAOException e) {
			throw e;
		} catch (Exception e) {
			throw new DAOException(slabUtils.makeErrorLog(logId, methodNm, e));
		}
		
	}
	
	/**
	 *      [A] 오퍼레이션명 : 하차작업예약생성 Renew
	 *  	
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param trnEqpCd,logId,modifier
	 * @return 
	 * @throws DAOException
	 */
	public void makeCarUdWrkBookReNew(String trnEqpCd,String logId, String modifier) throws DAOException {
		String methodNm = "하차작업예약생성 Renew [CarMvHdSeEJB.makeCarUdWrkBookReNew] < ";

		try{
			slabUtils.printLog(logId, methodNm, "S+");
		
			//운송장비코드로 차량스케줄id get
			String ydCarSchId = getYdCarSchIDByTrnEqpCd(trnEqpCd,logId);
			
			//차량이송재료 조회
			JDTORecord    recPara  = JDTORecordFactory.getInstance().create();
			recPara.setField("YD_CAR_SCH_ID", ydCarSchId);
			JDTORecordSet recSetRes = commDao.select(recPara, "com.inisteel.cim.yd.dao.ydcarftmvmtldao.YdCarftmvmtlDao.getYdCarftmvmtlID", logId, methodNm, "이송재료 조회"); 
			
			if(recSetRes == null || recSetRes.size() <=0 ) {
				slabUtils.printLog(logId,"운송장비코드 ["+trnEqpCd+"] 차량스케줄 ["+ydCarSchId+"] 이송재료 조회 실패", "SL");
				m_ctx.setRollbackOnly();
				throw new DAOException("운송장비코드 ["+trnEqpCd+"] 차량스케줄 ["+ydCarSchId+"] 이송재료 조회 실패");
			} 
			
			String ydAimYdGp  = slabUtils.trim(recSetRes.getRecord(0).getFieldString("YD_AIM_YD_GP"));
			String ydAimBayGp    = slabUtils.trim(recSetRes.getRecord(0).getFieldString("YD_AIM_BAY_GP"));

			String ydSchCd    = "";

			ydSchCd = ydAimYdGp + ydAimBayGp + "PT01LM"; //반입(제품통로)
			
			slabUtils.printLog(logId,"운송장비코드 ["+trnEqpCd+"] 스케줄코드 ["+ydSchCd+"] 기준조회 ", "SL");
			
			recPara.setField("YD_SCH_CD", ydSchCd);
			JDTORecordSet recSetRes2 = commDao.select(recPara, "com.inisteel.cim.yd.dao.ydschruledao.YdSchruleDao.getYdSchrule", logId, methodNm, "스케줄기준 조회"); 
			
			if(recSetRes2 == null || recSetRes2.size() <=0 ) {
				slabUtils.printLog(logId,"스케줄코드 ["+ydSchCd+"] 에 대한 스케줄기준 조회 불가", "SL");
				m_ctx.setRollbackOnly();
				throw new DAOException("스케줄코드 ["+ydSchCd+"] 에 대한 스케줄기준 조회 불가");
			} 
			
			//작업우선순위 추출
			String ydWrkCrnPrior = slabUtils.trim(recSetRes.getRecord(0).getFieldString("YD_WRK_CRN_PRIOR"));

			
			 //재료별 다른 작업예약 재료 여부 체크 
			for(int i=0; i<recSetRes.size() ; i++){
				 String stlNo = slabUtils.trim(recSetRes.getRecord(i).getFieldString("STL_NO"));
				 if(!this.chkYdWrkBookMtlAble(stlNo, logId)){
					 slabUtils.printLog(logId,"차량스케줄 ["+ydCarSchId+"] 재료번호 ["+stlNo+"] 등록된 작업예약 이미 존재", "SL");
					 m_ctx.setRollbackOnly();
					 throw new DAOException("차량스케줄 ["+ydCarSchId+"] 재료번호 ["+stlNo+"] 등록된 작업예약 이미 존재");
				 }
				
			}
			
			//작업예약 생성
			YdWrkbookDao    ydWrkbookDao    = new YdWrkbookDao(); 
			String ydWbookId = ydWrkbookDao.getYdWrkbookId();
			
			slabUtils.printLog(logId,"작업예약 ID ["+ydWbookId+"] 작업예약 등록", "SL");
			
			recPara  = JDTORecordFactory.getInstance().create();
			recPara.setField("YD_WBOOK_ID",      ydWbookId);
			recPara.setField("REGISTER",         modifier);
			recPara.setField("YD_GP",            ydAimYdGp);
			recPara.setField("YD_BAY_GP",        ydAimBayGp);
			recPara.setField("YD_AIM_YD_GP",     ydAimYdGp);
	    	recPara.setField("YD_AIM_BAY_GP",    ydAimBayGp);
	    	recPara.setField("YD_SCH_PRIOR", 	   ydWrkCrnPrior);
	    	recPara.setField("YD_SCH_CD",        ydSchCd);
	    	recPara.setField("TRN_EQP_CD",       trnEqpCd);
	    	recPara.setField("YD_CAR_USE_GP",    "L");
	    	
	    	commDao.insert(recPara, "com.inisteel.cim.yd.dao.ydwrkbookdao.YdWrkbookDao.insYdWrkbook", logId, methodNm, "작업예약 등록"); 
			
	    	//작업예약 재료 등록
			for(int i=0; i<recSetRes.size() ; i++){
				 String stlNo      = slabUtils.trim(recSetRes.getRecord(i).getFieldString("STL_NO"));
				 String ydStkBedNo = slabUtils.trim(recSetRes.getRecord(i).getFieldString("YD_STK_BED_NO"));
				 String ydStkLyrNo = slabUtils.trim(recSetRes.getRecord(i).getFieldString("YD_STK_LYR_NO"));
				 recPara  = JDTORecordFactory.getInstance().create();
				 recPara.setField("YD_WBOOK_ID",    ydWbookId);
				 recPara.setField("REGISTER",       modifier);
				 recPara.setField("YD_STK_BED_NO",  ydStkBedNo);
				 recPara.setField("YD_STK_LYR_NO",  ydStkLyrNo);
				 recPara.setField("STL_NO",         stlNo);
				 recPara.setField("YD_UP_COLL_SEQ", Integer.toString(i+1));
				 
				 slabUtils.printLog(logId,"작업예약 ID ["+ydWbookId+"] 재료번호 ["+stlNo+"] 작업예약 재료 등록", "SL");
				 
				 commDao.insert(recPara, "com.inisteel.cim.yd.dao.ydwrkbookmtldao.YdWrkbookmtlDao.insYdWrkbookmtl", logId, methodNm, "작업예약 재료 등록"); 
				
			}
			//차량 상태 하차출발로 업데이트
			updYdCarSchToUDLevByTrnEqpCd(trnEqpCd,ydWbookId,logId,modifier);

			slabUtils.printLog(logId, methodNm, "S-");

		} catch (DAOException e) {
			throw e;
		} catch (Exception e) {
			throw new DAOException(slabUtils.makeErrorLog(logId, methodNm, e));
		}
		
	}
	
	/**
	 *      [A] 오퍼레이션명 : 작업예약재료 등록가능 여부 체크
	 *  	
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param stlNo,logId
	 * @return 
	 * @throws DAOException
	 */
	public boolean chkYdWrkBookMtlAble(String stlNo,String logId ) throws DAOException {
		String methodNm = "작업예약재료 등록가능 여부 체크  [CarMvHdSeEJB.chkYdWrkBookMtlAble] < ";

		try{
			slabUtils.printLog(logId, methodNm, "S+");
		
			slabUtils.printLog(logId,"재료번호 ["+stlNo+"] 작업예약재료 등록 가능여부 체크", "SL");
			//작업예약재료 조회
			JDTORecord    recPara  = JDTORecordFactory.getInstance().create();
			recPara.setField("STL_NO", stlNo);
			JDTORecordSet recSetRes = commDao.select(recPara, "com.inisteel.cim.yd.dao.ydwrkbookmtldao.YdWrkbookmtlDao.getYdWrkbookmtlSTLNO", logId, methodNm, "작업예약 재료 조회"); 
						
			if(recSetRes == null || recSetRes.size() <=0 ) {
				slabUtils.printLog(logId,"재료번호 ["+stlNo+"] 작업예약재료 등록 가능", "SL");
				slabUtils.printLog(logId, methodNm, "S-");
				return true;
			} 
			slabUtils.printLog(logId, methodNm, "S-");
			return false;
		} catch (DAOException e) {
			throw e;
		} catch (Exception e) {
			throw new DAOException(slabUtils.makeErrorLog(logId, methodNm, e));
		}
		
	}

	/**
	 *      [A] 오퍼레이션명 : 각 야드별 저장품제원 전송 
	 *  	
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param trnEqpCd,logId
	 * @return 
	 * @throws DAOException
	 */
	public void sndStrStockSpecToL2(String trnEqpCd,String logId ) throws DAOException {
		String methodNm = "각 야드별 저장품제원 전송  [CarMvHdSeEJB.sndStrStockSpecToL2] < ";

		try{
			slabUtils.printLog(logId, methodNm, "S+");
			
			String ydCarSchId = getYdCarSchIDByTrnEqpCd(trnEqpCd,logId);
			
		
			//차량이송재료 조회
			JDTORecord    recPara  = JDTORecordFactory.getInstance().create();
			recPara.setField("YD_CAR_SCH_ID", ydCarSchId);
			JDTORecordSet recSetRes = commDao.select(recPara, "com.inisteel.cim.yd.dao.ydcarftmvmtldao.YdCarftmvmtlDao.getYdCarftmvmtlID", logId, methodNm, "이송재료 조회"); 
			
			if(recSetRes == null || recSetRes.size() <=0 ) {
				slabUtils.printLog(logId,"운송장비코드 ["+trnEqpCd+"] 차량스케줄 ["+ydCarSchId+"] 이송재료 조회 실패", "SL");
				m_ctx.setRollbackOnly();
				throw new DAOException("운송장비코드 ["+trnEqpCd+"] 차량스케줄 ["+ydCarSchId+"] 이송재료 조회 실패");
			}
			
			String ydAimYdGp  = slabUtils.trim(recSetRes.getRecord(0).getFieldString("YD_AIM_YD_GP"));
			String ydAimBayGp    = slabUtils.trim(recSetRes.getRecord(0).getFieldString("YD_AIM_BAY_GP"));
			String msgId = "";
			YdDelegate      ydDelegate      = new YdDelegate();
			
			if(YdConstant.YD_GP_C_SLAB_YARD.equals(ydAimYdGp)){
				msgId = "YDY1L002";
			} else if(YdConstant.YD_GP_PORT_SLAB_YARD.equals(ydAimYdGp)){
				msgId = "YDE7L002";
			}
			if("".equals(msgId)){
				slabUtils.printLog(logId,"운송장비코드 ["+trnEqpCd+"] 차량스케줄 ["+ydCarSchId+"] msgId 생성되지 않음", "SL");
				slabUtils.printLog(logId, methodNm, "S-");
				return;
			}
			
			for(int i=0; i<recSetRes.size(); i++){
				String stlNo = slabUtils.trim(recSetRes.getRecord(i).getFieldString("STL_NO"));
				recPara  = JDTORecordFactory.getInstance().create();
				recPara.setField("MSG_ID"			,msgId);
				recPara.setField("YD_INFO_SYNC_CD"	,"B");							//차량입고
				recPara.setField("STL_NO"			,stlNo);
				recPara.setField("YD_STK_COL_GP"	,ydAimYdGp);
				recPara.setField("YD_GP"			,ydAimYdGp); //2016.01.21 항만야드적용 LeeJY
				
				ydDelegate.sendMsg(recPara);
			}
			
			
			slabUtils.printLog(logId, methodNm, "S-");
		} catch (DAOException e) {
			throw e;
		} catch (Exception e) {
			throw new DAOException(slabUtils.makeErrorLog(logId, methodNm, e));
		}
		
	}
	
	/**
	 *      [A] 오퍼레이션명 : 소재차량도착실적 Renew
	 *  	
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param rcvMsg
	 * @return String
	 * @throws DAOException
	 */
	public String procMatlCarArrRenew(JDTORecord rcvMsg)throws DAOException{
		String methodNm = "소재차량도착실적 Renew  [CarMvHdSeEJB.procMatlCarArrRenew] < ";
		String logId = rcvMsg.getResultCode();
		
		try{
			slabUtils.printLog(logId, methodNm, "S+");
			
			//전문 id 확인 
			String rcvTcCode=ydUtils.getTcCode(rcvMsg);
			if(rcvTcCode ==null || "".equals(rcvTcCode)){
				slabUtils.printLog(logId,  "[" + methodNm + "] TC Code Error ["+rcvTcCode+"]", "SL");
				return YdConstant.RETN_CD_TC_ERROR;
			}
			String msgGp 			 = slabUtils.trim(rcvMsg.getFieldString("MSG_GP"));				//장비번호
			String arrWlocCd 		 = slabUtils.trim(rcvMsg.getFieldString("ARR_WLOC_CD"));		//발지개소
			String arrYdPntCd 		 = slabUtils.trim(rcvMsg.getFieldString("ARR_YD_PNT_CD"));		//발지포인트코드
			String trnEqpCd 		 = slabUtils.trim(rcvMsg.getFieldString("TRN_EQP_CD"));			//착지개소
			String trnWrkFullvoidGp  = slabUtils.trim(rcvMsg.getFieldString("TRN_WRK_FULLVOID_GP"));//공차영차 구분

			String modifier = "CarArrNew";
			
			slabUtils.printLog(logId,"차량도착전문 ["+rcvTcCode+"] 운송장비코드 ["+trnEqpCd+"] 처리 ", "SL");
			slabUtils.printLog(logId,"전문내용 착지개소["+arrWlocCd+"] 착지 포인트 ["+arrYdPntCd+"] ", "SL");
			slabUtils.printLog(logId,"전문내용 공차영차 구분 ["+trnWrkFullvoidGp+"]", "SL");
		
			//적치열 활성상태 확인 
			if(!chkCarpointAble(arrWlocCd,arrYdPntCd,logId)){
				slabUtils.printLog(logId,"개소코드 ["+arrWlocCd+"] 포인트["+arrYdPntCd+"] 사용 불가", "SL");
				m_ctx.setRollbackOnly();
				throw new DAOException("개소코드 ["+arrWlocCd+"] 포인트["+arrYdPntCd+"] 사용 불가");
			}
			
			//도착처리 정상 리턴 처리 여부 체크 
			if(chkCarArrNormalReturn(rcvMsg,logId)){
				slabUtils.printLog(logId, methodNm, "S-");
				return YdConstant.RETN_CD_SUCCESS;
			}
			
			//개소코드 ->야드코드 변경
			String ydGp = YdCommonUtils.getYdFromWlocCd(arrWlocCd);
			
			//공차 도착 실적
			if(YdConstant.TRN_WRK_VOID.equals(trnWrkFullvoidGp)){
				if(YdConstant.YD_GP_C_SLAB_YARD.equals(ydGp)
				|| YdConstant.YD_GP_PORT_SLAB_YARD.equals(ydGp)
				  ){
					this.procLDMatlCarArrNew(rcvMsg,logId);
				}
				//야드코드 F(후판정정) or % (DJY24 재열재) 
				else {
					//this.procLDMatlCarArrNew(rcvMsg,logId);
				}
			}
			//영차 도착 실적
			else {
				//this.procUDMatlCarArrNew(rcvMsg,logId);
			}
			
			
			slabUtils.printLog(logId, methodNm, "S-");
			return YdConstant.RETN_CD_SUCCESS;
		} catch (DAOException e) {
			throw e;
		} catch (Exception e) {
			throw new DAOException(slabUtils.makeErrorLog(logId, methodNm, e));
		}
		
	}
	
	/**
	 *      [A] 오퍼레이션명 : 차량포인트 사용가능여부 확인
	 *  	
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param rcvMsg, logId
	 * @return boolean
	 * @throws DAOException
	 */
	public boolean chkCarpointAble (String wlocCd, String ydPntCd, String logId)throws DAOException {
		String methodNm = "차량포인트 사용가능여부 확인 [CarMvHdSeEJB.chkCarpointAble] < ";

		try{
			slabUtils.printLog(logId, methodNm, "S+");

			JDTORecord recPara  = JDTORecordFactory.getInstance().create();
			recPara.setField("WLOC_CD", wlocCd);
			recPara.setField("ydPntCd", ydPntCd);
			JDTORecordSet recSetRes = commDao.select(recPara, "com.inisteel.cim.yd.dao.ydstkcoldao.YdStkcolDao.getYdStkcolWLocCdandPntCd", logId, methodNm, "차량포인트 사용가능여부 확인"); 
			
			if(recSetRes ==null || recSetRes.size() <= 0) {	
				slabUtils.printLog(logId,"개소코드 ["+wlocCd+"] 포인트["+ydPntCd+"] 존재하지 않음", "SL");
				m_ctx.setRollbackOnly();
				throw new DAOException("개소코드 ["+wlocCd+"] 포인트["+ydPntCd+"] 존재하지 않음");
			} 
			String ydStkColActStat = slabUtils.trim(recSetRes.getRecord(0).getFieldString("YD_STK_COL_ACT_STAT"));

			slabUtils.printLog(logId,"개소코드 ["+wlocCd+"] 포인트["+ydPntCd+"] 적치열 활성상태 ["+ydStkColActStat+"]", "SL");
			
			if(YdConstant.YD_STK_COL_ACTIVE.equals(ydStkColActStat)){
				slabUtils.printLog(logId,"상차 정지위치가 이미 활성상태 입니다.", "SL");
				return false;
			}
			else if(YdConstant.YD_STK_COL_NOUSE.equals(ydStkColActStat)){
				slabUtils.printLog(logId,"상차 정지위치가 사용불가 상태입니다.", "SL");
				return false;
			}
			
			slabUtils.printLog(logId, methodNm, "S-");
			
			return true;

		} catch (DAOException e) {
			throw e;
		} catch (Exception e) {
			throw new DAOException(slabUtils.makeErrorLog(logId, methodNm, e));
		}
		
	}
