	/**
	 *      [A] 오퍼레이션명 : 차량도착처리 로직 return 체크
	 *  	
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param rcvMsg, logId
	 * @return boolean
	 * @throws DAOException
	 */
	public boolean chkCarArrNormalReturn (JDTORecord rcvMsg,String logId)throws DAOException {
		String methodNm = "차량도착처리 로직 return 체크 [CarMvHdSeEJB.chkCarArrNormalReturn] < ";

		try{
			slabUtils.printLog(logId, methodNm, "S+");
			
			String msgGp 			 = slabUtils.trim(rcvMsg.getFieldString("MSG_GP"));				//장비번호
			String arrWlocCd 		 = slabUtils.trim(rcvMsg.getFieldString("ARR_WLOC_CD"));		//발지개소
			String arrYdPntCd 		 = slabUtils.trim(rcvMsg.getFieldString("ARR_YD_PNT_CD"));		//발지포인트코드
			String trnEqpCd 		 = slabUtils.trim(rcvMsg.getFieldString("TRN_EQP_CD"));			//착지개소
			String trnWrkFullvoidGp  = slabUtils.trim(rcvMsg.getFieldString("TRN_WRK_FULLVOID_GP"));//공차영차 구분
			
			String modifier = "CarArrRet"; 
			
			//1. 착지개소코드 대기장 확인
			if( YdConstant.YD_WAIT_PNT_CD.equals(arrYdPntCd) ) {
				slabUtils.printLog(logId,"착지개소코드 ["+arrWlocCd+"] 착지포인트코드 ["+arrYdPntCd+"] 가 대기장이므로 업무처리 종료 ", "SL");
				slabUtils.printLog(logId, methodNm, "S-");
				return true;
	    	}
			
			if( YdConstant.YD_REPAIR_WLOC_CD.equals(arrWlocCd) ) {
				slabUtils.printLog(logId,"착지개소코드 ["+arrWlocCd+"] 가 대기장이므로 업무처리 종료 ", "SL");
				slabUtils.printLog(logId, methodNm, "S-");
				return true;
	    	}
			//2. 운송장비코드로 차량스케줄 존재 확인
			JDTORecord    recPara  = JDTORecordFactory.getInstance().create();
			recPara.setField("TRN_EQP_CD", trnEqpCd);
			JDTORecordSet recSetRes = commDao.select(recPara, "com.inisteel.cim.yd.dao.ydcarschdao.YdCarschDao.getYdCarschDaoTrnEqpCd", logId, methodNm, "차량스케줄 조회"); 
			
			if(recSetRes ==null || recSetRes.size() <= 0) {	
				slabUtils.printLog(logId,"운송장비코드 ["+trnEqpCd+"] 차량스케줄 조회 실패", "SL");
				m_ctx.setRollbackOnly();
				throw new DAOException("운송장비코드 ["+trnEqpCd+"] 차량스케줄 조회 실패");
			} 
			
			//3.차량 스케줄 존재시 중복도착 체크하여 종료처리 
			String ydCarSchId = slabUtils.trim(recSetRes.getRecord(0).getFieldString("YD_CAR_SCH_ID"));
			String ydCarProgStat = slabUtils.trim(recSetRes.getRecord(0).getFieldString("YD_CAR_PROG_STAT"));
		
			
			slabUtils.printLog(logId,"운송장비코드 ["+trnEqpCd+"] 차량스케줄 ["+ydCarSchId+"] 차량상태 ["+ydCarProgStat+"]", "SL");
			
			//도착전문이 수정전문이 아니고, 이미 상차/하차 도착한 상태는 중복 도착처리이므로 업무처리 종료
			if(!"U".equals(msgGp)&&
					(YdConstant.YD_CARLD_ARR.equals(ydCarProgStat) || YdConstant.YD_CARUD_ARR.equals(ydCarProgStat))
				){
				slabUtils.printLog(logId,"운송장비코드 ["+trnEqpCd+"] 차량스케줄 ["+ydCarSchId+"] "
						+ "차량상태 ["+ydCarProgStat+"] 메세지 구분 ["+msgGp+"] 중복도착처리는 종료", "SL");
				slabUtils.printLog(logId, methodNm, "S-");
				return true;
			}
			
			//4.관리되지 않는 개소코드인경우 차량상태 하차도착으로 변경 후 종료
			if(   (    YdConstant.WLOC_CD_A_PLATE_PLANT.equals(arrWlocCd) 
					|| YdConstant.WLOC_CD_B_PLATE_PLANT.equals(arrWlocCd)
					|| YdConstant.WLOC_CD_C_HR_PLANT.equals(arrWlocCd)
				   )
					&& "F".equals(trnWrkFullvoidGp)){
				
				slabUtils.printLog(logId,"착지개소코드 ["+arrWlocCd+"] 가 관리되지 않는 개소코드이므로 차량스케줄만 하차도착 처리 후 종료", "SL");
				
				
				updYdCarSchToUDArrByTrnEqpCd(trnEqpCd ,arrWlocCd ,null,logId ,modifier);
				
			}
			
			//5. 해당 차량으로 만들어져있는 크레인스케줄 체크하여, 선택상태일시, 재도착처리 불가.
			
			
			slabUtils.printLog(logId, methodNm, "S-");
			
			return false;

		} catch (DAOException e) {
			throw e;
		} catch (Exception e) {
			throw new DAOException(slabUtils.makeErrorLog(logId, methodNm, e));
		}
		
	}
	
