	/**
	 *      [A] 오퍼레이션명 : 차량작업재료 지상절단 실적 등록 대상재 포함 체크 
	 *      차량 작업재료가 TB_CS_BASESTTN_TRIM_WR 테이블에 존재하는지 체크
	 *  	
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param ydCarSchId,logId
	 * @return 
	 * @throws DAOException
	 */
	public boolean chkCarMvMtlInBaseTrim(String ydCarSchId,String logId ) throws DAOException {
		String methodNm = "차량작업재료 지상절단 실적 등록 대상재 포함 체크  [CarMvHdSeEJB.chkCarMvMtlInBaseTrim] < ";

		try{
			slabUtils.printLog(logId, methodNm, "S+");
		
			slabUtils.printLog(logId,"차량스케줄 ["+ydCarSchId+"] 지상절단 실적 등록 재료 포함여부 체크", "SL");
			//작업예약재료 조회
			JDTORecord    recPara  = JDTORecordFactory.getInstance().create();
			recPara.setField("YD_CAR_SCH_ID", ydCarSchId);
			JDTORecordSet recSetRes = commDao.select(recPara, "com.inisteel.cim.yd.slabyd.dao.SlabYdCommDAO.chkCarMvMtlInBaseTrim", logId, methodNm, "작업예약 재료 조회"); 
						
			if(recSetRes == null || recSetRes.size() <=0 ) {
				slabUtils.printLog(logId,"차량스케줄 ["+ydCarSchId+"] 지상절단 실적 등록 재료 포함 안함", "SL");
				slabUtils.printLog(logId, methodNm, "S-");
				return false;
			} 
			
			int cntBaseTrim = Integer.parseInt(slabUtils.trim(recSetRes.getRecord(0).getFieldString("CNT_BASE_TRIM")));

			//지상절단 실적 등록 재료 포함했을시 true 리턴
			if(cntBaseTrim >0) {
				slabUtils.printLog(logId,"차량스케줄 ["+ydCarSchId+"] 지상절단 실적 등록 재료 포함 ["+cntBaseTrim+"] 매 ", "SL");
				slabUtils.printLog(logId, methodNm, "S-");
				return true;
			}
			
			
			slabUtils.printLog(logId, methodNm, "S-");
			return false;
		} catch (DAOException e) {
			throw e;
		} catch (Exception e) {
			throw new DAOException(slabUtils.makeErrorLog(logId, methodNm, e));
		}
		
	}
	
	/**
	 *      [A] 오퍼레이션명 : 차량작업재료 지상절단 실적 등록 대상재 포함 체크 
	 *      차량 작업재료가 TB_CS_BASESTTN_TRIM_WR 테이블에 존재하는지 체크
	 *  	
	 * @ejb.interface-method EJBDoclet을 생성하는 태그입니다.
	 * @param ydCarSchId,logId
	 * @return 
	 * @throws DAOException
	 */
	public int chkCarMvMtlInStoAPlate(String ydCarSchId,String logId ) throws DAOException {
		String methodNm = "차량작업재료 통합 ->연주 후판재 확인[CarMvHdSeEJB.chkCarMvMtlInStoAPlate] < ";

		try{
			slabUtils.printLog(logId, methodNm, "S+");
		
			int code = 0;
			slabUtils.printLog(logId,"차량스케줄 ["+ydCarSchId+"] 통합 ->연주 후판재  체크", "SL");
			slabUtils.printLog(logId,"해당없을시 0, 스카핑대상재 1, 스카핑 미대상재(완료재) 2", "SL");
			//작업예약재료 조회
			JDTORecord    recPara  = JDTORecordFactory.getInstance().create();
			recPara.setField("YD_CAR_SCH_ID", ydCarSchId);
			JDTORecordSet recSetRes = commDao.select(recPara, "com.inisteel.cim.yd.slabyd.dao.SlabYdCommDAO.chkCarMvMtlInStoAPlate", logId, methodNm, "작업예약 재료 조회"); 
						
			if(recSetRes == null || recSetRes.size() <=0 ) {
				slabUtils.printLog(logId,"차량스케줄 ["+ydCarSchId+"] 통합 -> 연주 후판재 포함 안함", "SL");
				slabUtils.printLog(logId, methodNm, "S-");
				return 0;
			} 
			
			code = Integer.parseInt(slabUtils.trim(recSetRes.getRecord(0).getFieldString("CODE")));

			//지상절단 실적 등록 재료 포함했을시 true 리턴
			if(code == 0){
				slabUtils.printLog(logId,"차량스케줄 ["+ydCarSchId+"] 통합 -> 연주 후판재 포함 안함", "SL");
			}
			else if (code ==1){
				slabUtils.printLog(logId,"차량스케줄 ["+ydCarSchId+"] 통합 -> 연주 후판재 스카핑 미완료재 포함", "SL");
			}
			else if (code ==2){
				slabUtils.printLog(logId,"차량스케줄 ["+ydCarSchId+"] 통합 -> 연주 후판재 스카핑 완료재 포함", "SL");
			}
			
			
			slabUtils.printLog(logId, methodNm, "S-");
			return code;
		} catch (DAOException e) {
			throw e;
		} catch (Exception e) {
			throw new DAOException(slabUtils.makeErrorLog(logId, methodNm, e));
		}
		
	}
	
